
 (gc .\2026\2026necmp2_matches.js).replace("var schedule = ","") | ConvertFrom-Json | % { $_ | select match_number, @{N="Red1";E={$_.alliances.red.team_keys[0]}}, @{N="Red2";E={$_.alliances.red.team_keys[1]}},@{N="Red3";E={$_.alliances.red.team_keys[2]}}, @{N="Blue1";E={$_.alliances.blue.team_keys[0]}}, @{N="Blue2";E={$_.alliances.blue.team_keys[1]}},@{N="Blue3";E={$_.alliances.blue.team_keys[2]}}, @{N="PredictedStart";E={[datetime]$origin = '1970-01-01 00:00:00'; $origin.AddSeconds([int]$_.time).ToLocalTime()}} } | sort {[int]$_.match_number }